  ('aboriginal-f7485f85-moex-00022', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司自 X5 年起銷售一款新產品，提供兩年保固。依同業與本公司經驗，保固成本占銷貨收入 比率於出售後第一年估計為2.5%，出售後第二年估計為5.5%。X5與X6年度之銷貨與實際已支 付保固費用如下： X5年：銷貨$420,000；已發生保固支出$10,000 X6年：銷貨$560,000；已發生保固支出$22,000 試問截至X6年12月31日應列報之估計產品保固負債餘額為何？', '["$44,800", "$46,400", "$48,000", "$52,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
  ('aboriginal-f7485f85-moex-00023', 'aboriginal-f7485f85', 'aboriginal-f7485f85-moex-114-d35177eb', 'sub-aboriginal-f7485f85-01', NULL, 'single_choice', '甲公司於X5年度的相關資料如下：本期稅後淨利$360,000；處分機器收現$240,000（其中包含出 售利益$80,000）；折舊費用$70,000；提列預期信用減損損失$30,000；應收帳款淨額增加$50,000。 請計算X5年度來自營業活動之現金流量為何？', '["$300,000", "$330,000", "$350,000", "$370,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:08+00:00", "source_pdf_sha1": "fdd87a649633", "answer_pdf_sha1": "074507e641f2", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "201", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "外交行政人員"}'::jsonb, NULL),
